#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct { int hit; float t, px, py, pz, nx, ny, nz; } Hit;

static Hit sphere(float cx, float cy, float cz, float r,
                  float ox, float oy, float oz,
                  float dx, float dy, float dz) {
    Hit h; h.hit = 0;
    float Lx = ox - cx, Ly = oy - cy, Lz = oz - cz;
    float a = (dx * dx + dy * dy) + dz * dz;
    float dl = (Lx * dx + Ly * dy) + Lz * dz;
    float b = dl + dl;
    float c = (Lx * Lx + Ly * Ly + Lz * Lz) - r * r;
    float disc = b * b - 4.0f * a * c;
    if (disc < 0.0f) return h;
    double nb = -(double)b;
    double sq = sqrt((double)disc);
    double a2 = (double)(a + a);
    float t = (float)((nb - sq) / a2);
    if (!(t >= 0.001f)) {
        t = (float)((nb + sq) / a2);
        if (!(t >= 0.001f)) return h;
    }
    float hx = ox + t * dx, hy = oy + t * dy, hz = oz + t * dz;
    float mx = hx - cx, my = hy - cy, mz = hz - cz;
    float ln = sqrtf((mx * mx + my * my) + mz * mz);
    h.hit = 1; h.t = t;
    h.px = hx; h.py = hy; h.pz = hz;
    h.nx = mx / ln; h.ny = my / ln; h.nz = mz / ln;
    return h;
}

int main(void) {
    int W = 800, H = 600;
    fprintf(stderr, "Creating high-resolution image: %dx%d\n", W, H);
    fprintf(stderr, "This will be downsampled with ffmpeg after rendering\n");
    fprintf(stderr, "Rendering high-resolution image...\n");

    float ll = sqrtf((1.0f * 1.0f + 1.0f * 1.0f) + (-1.0f) * (-1.0f));
    float lx = 1.0f / ll, ly = 1.0f / ll, lz = -1.0f / ll;
    float sl = sqrtf((lx * lx + ly * ly) + lz * lz);
    float sdx = lx / sl, sdy = ly / sl, sdz = lz / sl;

    float **img = malloc((size_t)H * sizeof(float *));
    for (int i = 0; i < H; i++) img[i] = malloc((size_t)3 * W * sizeof(float));

    for (int y = 0; y < H; y++) {
        fprintf(stderr, "\rProgress: %.1f%%", (double)((100.0f * (float)y) / 600.0f));
        float V = 1.0f - (float)y / 599.0f; V = V + V;
        for (int x = 0; x < W; x++) {
            float fx = (float)x / 799.0f;
            float dx = fx * 2.6666667f - 1.3333334f;
            float dy = V - 1.0f;
            float dz = -1.0f;
            float dn = sqrtf((dx * dx + dy * dy) + dz * dz);
            dx /= dn; dy /= dn; dz /= dn;

            Hit s = sphere(0.0f, -0.5f, -5.0f, 1.0f, 0.0f, 0.0f, 0.0f, dx, dy, dz);

            int planev = 0;
            float tp = 0, ppx = 0, ppy = 0, ppz = 0;
            if (fabsf(dy) >= 1e-4f) {
                tp = -1.5f / dy;
                if (tp >= 0.001f) {
                    planev = 1;
                    ppx = dx * tp; ppy = dy * tp; ppz = dz * tp;
                }
            }

            int mat;
            if (s.hit && planev) mat = (tp > s.t) ? 1 : 0;
            else if (s.hit) mat = 1;
            else if (planev) mat = 0;
            else mat = -1;

            float *pix = &img[y][x * 3];
            if (mat < 0) {
                float t = (dy + 1.0f) * 0.5f;
                float omt = 1.0f - t;
                pix[0] = t * 0.5f + omt;
                pix[1] = t * 0.7f + omt;
                pix[2] = t + omt;
                continue;
            }

            float px, py, pz, nx, ny, nz;
            if (mat == 1) {
                px = s.px; py = s.py; pz = s.pz;
                nx = s.nx; ny = s.ny; nz = s.nz;
            } else {
                px = ppx; py = ppy; pz = ppz;
                nx = 0.0f; ny = 1.0f; nz = 0.0f;
            }

            Hit sh = sphere(0.0f, -0.5f, -5.0f, 1.0f, px, py, pz, sdx, sdy, sdz);
            float diff;
            if (!sh.hit) {
                float dot = (nx * lx + ny * ly) + nz * lz;
                float m = (float)fmax((double)dot, 0.0);
                diff = m * 0.8f + 0.2f;
            } else {
                diff = 0.2f;
            }

            if (mat == 1) {
                pix[0] = diff;
                pix[1] = 0.2f * diff;
                pix[2] = 0.2f * diff;
            } else {
                long k = (long)((double)floorf(pz) + (double)floorf(px));
                float ch = (k & 1) ? 0.4f : 0.9f;
                float cc = ch * diff;
                pix[0] = cc; pix[1] = cc; pix[2] = cc;
            }
        }
    }
    fprintf(stderr, "\nRendering complete\n");

    FILE *fp = fopen("image.ppm", "w");
    fprintf(fp, "P3\n%d %d\n255\n", W, H);
    for (int y = 0; y < H; y++) {
        for (int x = 0; x < W; x++) {
            float *pix = &img[y][x * 3];
            int v[3];
            for (int cch = 0; cch < 3; cch++) {
                double vv = fmin(fmax((double)pix[cch], 0.0), 1.0);
                v[cch] = (int)((float)vv * 255.99f);
            }
            fprintf(fp, "%d %d %d\n", v[0], v[1], v[2]);
        }
    }
    fclose(fp);
    fprintf(stderr, "Wrote image to %s\n", "image.ppm");

    for (int i = 0; i < H; i++) free(img[i]);
    free(img);
    fprintf(stderr, "Done.\n");
    return 0;
}

